CREATE TABLE IF NOT EXISTS settings (key TEXT PRIMARY KEY, value TEXT NOT NULL, value_type TEXT NOT NULL DEFAULT 'number', updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS customers (id TEXT PRIMARY KEY, name TEXT NOT NULL, phone TEXT NOT NULL, email TEXT NOT NULL, city TEXT, state TEXT, pincode TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS leads (id TEXT PRIMARY KEY, customer_id TEXT NOT NULL REFERENCES customers(id), property_type TEXT NOT NULL, roof_type TEXT NOT NULL, ownership TEXT NOT NULL, monthly_bill INTEGER NOT NULL, monthly_units INTEGER, provider TEXT, bill_object_key TEXT, status TEXT NOT NULL DEFAULT 'new', assigned_to TEXT, notes TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS quotes (id TEXT PRIMARY KEY, lead_id TEXT NOT NULL REFERENCES leads(id), engine_version TEXT NOT NULL, settings_snapshot TEXT NOT NULL, result_json TEXT NOT NULL, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS pricing (id TEXT PRIMARY KEY, name TEXT NOT NULL, value REAL NOT NULL, unit TEXT, active INTEGER NOT NULL DEFAULT 1, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS subsidy_rules (id TEXT PRIMARY KEY, name TEXT NOT NULL, amount_per_kw REAL NOT NULL, cap REAL NOT NULL, property_type TEXT, active INTEGER NOT NULL DEFAULT 1);
CREATE TABLE IF NOT EXISTS admins (id TEXT PRIMARY KEY, email TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, role TEXT NOT NULL DEFAULT 'salesperson', active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS lead_notes (id TEXT PRIMARY KEY, lead_id TEXT NOT NULL REFERENCES leads(id), admin_id TEXT NOT NULL REFERENCES admins(id), note TEXT NOT NULL, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS lead_status_history (id TEXT PRIMARY KEY, lead_id TEXT NOT NULL REFERENCES leads(id), status TEXT NOT NULL, admin_id TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS salesperson_assignments (lead_id TEXT PRIMARY KEY REFERENCES leads(id), admin_id TEXT NOT NULL REFERENCES admins(id), assigned_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
